std::vector<long long> solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n == 0) {
        return {};
    }

    // The first and last elements are always valid.
    std::vector<long long> result;
    if (n > 0) {
        result.push_back(nums[0]);
    }
    if (n > 1) {
        result.push_back(nums[n - 1]);
    }

    if (n <= 2) {
        return result;
    }

    // Precompute left maximums: left_max[i] is the maximum element in nums[0...i-1]
    std::vector<long long> left_max(n);
    left_max[0] = -1; // Sentinel value, smaller than any possible element
    for (int i = 1; i < n; ++i) {
        left_max[i] = std::max(nums[0], nums[1]); // Initialize with first two elements' comparison base
        for (int j = 0; j < i; ++j) {
            left_max[i] = std::max(left_max[i], nums[j]);
        }
    }

    // Precompute right maximums: right_max[i] is the maximum element in nums[i+1...n-1]
    std::vector<long long> right_max(n);
    right_max[n - 1] = -1; // Sentinel value
    for (int i = n - 2; i >= 0; --i) {
        right_max[i] = nums[n - 1]; // Initialize with last element
        for (int j = i + 1; j < n; ++j) {
            right_max[i] = std::max(right_max[i], nums[j]);
        }
    }

    // A more efficient O(N) precomputation for maxes:

    // 1. Left maximums (L[i] = max(nums[0]...nums[i-1]))
    std::vector<long long> L(n);
    L[0] = -1; // No elements to the left of index 0
    long long current_max = nums[0];
